"use strict";(self.webpackChunkrrbtc_wiki_docusaurus=self.webpackChunkrrbtc_wiki_docusaurus||[]).push([[36137],{15332(i){i.exports=JSON.parse('{"tag":{"label":"bitcoin","permalink":"/tags/bitcoin","allTagsPath":"/tags","count":12,"items":[{"id":"concepts/bitcoin-address-types","title":"Bitcoin Address Types","description":"Comparison of Bitcoin address formats including Legacy, P2SH, SegWit (Bech32), native SegWit, and Taproot, with guidance on which to use for compatibility, privacy, and future-proofing.","permalink":"/concepts/bitcoin-address-types"},{"id":"entities/bitcoin-core","title":"Bitcoin Core","description":"Bitcoin Core is the reference implementation of the Bitcoin protocol. Originally released by Satoshi Nakamoto in 2009 as \\"Bitcoin,\\" it remains the most widely used, reviewed, and trusted node software.","permalink":"/entities/bitcoin-core"},{"id":"comparisons/bitcoin-core-vs-knots","title":"Bitcoin Core vs Bitcoin Knots","description":"Neutral comparison of Bitcoin Core and Bitcoin Knots consensus rules, mempool policies, BIP-110/RDTS differences, and guidance on choosing based on your transaction filtering preferences.","permalink":"/comparisons/bitcoin-core-vs-knots"},{"id":"concepts/bitcoin-node-types","title":"Bitcoin Node Types","description":"Comparison of full, pruned, archival, Simplified Payment Verification (SPV), and neutral nodes; explains trade-offs in storage, trust, privacy, and validation guarantees.","permalink":"/concepts/bitcoin-node-types"},{"id":"concepts/bitcoin-protocol","title":"Bitcoin Protocol","description":"Survey of the Bitcoin protocol layer including consensus rules, peer-to-peer messaging, mempool policy, and the BIP process for proposing changes.","permalink":"/concepts/bitcoin-protocol"},{"id":"concepts/no-kyc-acquisition","title":"No-KYC Acquisition Methods","description":"Methods for acquiring Bitcoin without identity verification including Bisq, RoboSats, HodlHodl, Azteco vouchers, Bitcoin ATMs, and in-person trades.","permalink":"/concepts/no-kyc-acquisition"},{"id":"summaries/privacy-as-a-spectrum","title":"Privacy as a Spectrum","description":"Continuum of Bitcoin privacy from basic hygiene (address reuse avoidance, Tor) to advanced techniques (CoinJoin, Silent Payments, lightning, Nostr) \u2014 matched to user capability and threat model.","permalink":"/summaries/privacy-as-a-spectrum"},{"id":"concepts/privacy-stacks","title":"Privacy Stacks","description":"Modular compositions of tools for on-chain, Lightning, and metadata privacy \u2014 including CoinJoin, Silent Payments, Tor, and Nostr/SSH isolation.","permalink":"/concepts/privacy-stacks"},{"id":"comparisons/privacy-stacks","title":"Privacy Stacks \u2014 CoinJoin and No-KYC Acquisition","description":"Modular on-chain, Lightning, and metadata privacy stack compositions \u2014 compares CoinJoin, Silent Payments, Tor, Nostr, and SSH isolation approaches for different threat models.","permalink":"/comparisons/privacy-stacks"},{"id":"concepts/proof-of-work","title":"Proof of Work & Bitcoin Supply","description":"Fundamentals of Nakamoto consensus, difficulty adjustment, hash rate measurement, energy economics, and the security model underlying Bitcoin\'s immutability.","permalink":"/concepts/proof-of-work"},{"id":"entities/start-os","title":"StartOS","description":"StartOS (formerly Start9OS) is a Debian-based operating system designed specifically for self-hosting Bitcoin and Lightning infrastructure. It packages complex services into one-click installs with automatic Tor and LAN access.","permalink":"/entities/start-os"},{"id":"concepts/utxo-model","title":"UTXO Model","description":"Explanation of the UTXO accounting model, coin selection, consolidation, dust limits, and how UTXO management affects privacy, fees, and wallet performance.","permalink":"/concepts/utxo-model"}],"unlisted":false}}')}}]);